1	/**
2	 * Checkout state machine — coordinates the full checkout/check-in lifecycle.
3	 * This is the orchestrator: it calls damClient, fileOps, uploadQueue, and
4	 * chokidar to drive a checkout from start to finish.
5	 */
6	
7	import { shell } from "electron";
8	import chokidar, { FSWatcher } from "chokidar";
9	import { existsSync, statSync } from "fs";
10	import { join, dirname, basename } from "path";
11	import {
12	  resolveAssetPath,
13	  copyToWorkspace,
14	  writeCheckoutMeta,
15	  waitForFileStable,
16	  createSnapshot,
17	  checkoutDir,
18	} from "./fileOps";
19	import { sha256File } from "./hash";
20	import {
21	  startCheckout as apiStartCheckout,
22	  prepareCheckin as apiPrepareCheckin,
23	  discardCheckout as apiDiscard,
24	  getOpenCheckouts,
25	  redrive as apiRedrive,
26	} from "./damClient";
27	import { enqueue } from "./uploadQueue";
28	import { getConfig } from "./config";
29	import { validateRoot } from "./rootValidator";
30	import {
31	  getSeafileHealth,
32	  resolveSeafileTarget,
33	  ensureHydrated,
34	  getSeafileObjId,
35	} from "./seafileAdapter";
36	import { log } from "./logger";
37	import type { CheckoutRecord, RootMapping, StorageProvider } from "@shared/types";
38	
39	// In-memory map of active checkouts: checkoutId → record
40	const active = new Map<string, CheckoutRecord>();
41	// File watchers keyed by checkoutId
42	const watchers = new Map<string, FSWatcher>();
43	// Checkouts currently being re-driven, to avoid double-enqueuing before the
44	// server clears redrive_requested.
45	const redriving = new Set<string>();
46	
47	let changeListener: (() => void) | null = null;
48	
49	export function onCheckoutsChanged(cb: () => void): void {
50	  changeListener = cb;
51	}
52	
53	function notify(): void {
54	  changeListener?.();
55	}
56	
57	// ── Load from server on startup ───────────────────────────────────────────────
58	
59	export async function loadActiveCheckouts(): Promise<void> {
60	  try {
61	    const res = await getOpenCheckouts();
62	    const config = getConfig();
63	    for (const co of res.checkouts ?? []) {
64	      const assetInfo = (co as any).assets ?? {};
65	      const record: CheckoutRecord = {
66	        id: co.id,
67	        assetId: assetInfo.id ?? "",
68	        userId: "",
69	        deviceId: null,
70	        status: co.status as CheckoutRecord["status"],
71	        checkedOutAt: co.checked_out_at,
72	        checkedInAt: null,
73	        filename: assetInfo.filename ?? "",
74	        relativePath: assetInfo.relative_path ?? "",
75	        rootId: "",
76	        sourceHash: co.source_hash,
77	        sourceSize: co.source_size,
78	        workspacePath: join(
79	          checkoutDir(config.workspacePath, co.id),
80	          assetInfo.filename ?? "",
81	        ),
82	        snapshotPath: null,
83	        uploadProgress: null,
84	        errorMessage: null,
85	      };
86	      active.set(co.id, record);
87	      watchFile(co.id, record.workspacePath);
88	    }
89	    notify();
90	  } catch (e) {
91	    log.warn("Failed to load active checkouts from server:", e);
92	  }
93	}
94	
95	// ── Checkout ──────────────────────────────────────────────────────────────────
96	
97	export async function checkout(
98	  token: string,
99	  assetId?: string,
100	): Promise<{ checkoutId: string; workspacePath: string }> {
101	  const config = getConfig();
102	
103	  const res = await apiStartCheckout({
104	    token,
105	    asset_id: assetId,
106	    device_id: config.deviceId,
107	    helper_version: config.helperVersion,
108	    computer_id: config.deviceName,
109	  });
110	
111	  const { checkout_id, asset, root_mappings } = res;
112	
113	  // Merge server root_mappings with locally saved paths
114	  const localMappings = config.rootMappings;
115	  const mergedMappings: RootMapping[] = root_mappings.map((rm: any) => {
116	    const local = localMappings.find((l) => l.root_id === rm.root_id);
117	    return {
118	      root_id: rm.root_id,
119	      display_name: rm.display_name ?? rm.root_id,
120	      local_path: local?.local_path ?? rm.local_path ?? "",
121	      marker_verified: local?.marker_verified ?? false,
122	    };
123	  });
124	
125	  // Double-check each mapping's local path is still pointing at the right folder level
126	  for (const mapping of mergedMappings) {
127	    if (!mapping.local_path) continue;
128	    const vResult = validateRoot(mapping.local_path, mapping.root_id);
129	    if (!vResult.ok) {
130	      if (vResult.reason === "too_deep" || vResult.reason === "too_shallow") {
131	        // Auto-correct in memory for this checkout — user should fix in Settings
132	        log.warn(`Root path level mismatch for "${mapping.root_id}" — correcting to ${vResult.suggestedPath}`);
133	        mapping.local_path = vResult.suggestedPath;
134	      } else if (vResult.reason === "wrong_root_id") {
135	        throw new Error(
136	          `Folder mapping for "${mapping.root_id}" points to the wrong NAS root ("${vResult.actual}"). Please fix your folder mappings in Settings.`,
137	        );
138	      }
139	      // no_marker and forbidden are non-blocking here — resolveAssetPath will fail if path is truly wrong
140	    }
141	  }
142	
143	  const rootId = asset.relative_path.split("/")[0] ?? asset.relative_path.split("\\")[0];
144	  const preferred: StorageProvider = config.preferredProvider ?? "seafile";
145	
146	  const resolveSynologyPath = (): string => {
147	    try {
148	      return resolveAssetPath(rootId, asset.relative_path, mergedMappings);
149	    } catch {
150	      throw new Error(
151	        `No local path configured for this asset. Please set up your folder mappings in Settings.`,
152	      );
153	    }
154	  };
155	
156	  let sourcePath: string | null = null;
157	  let sourceProvider: StorageProvider = "synology";
158	  let seafileObjId: string | undefined;
159	
160	  if (preferred === "seafile") {
161	    const health = getSeafileHealth(config);
162	    if (health.available) {
163	      try {
164	        const target = resolveSeafileTarget(asset.relative_path, config);
165	        // Confirm the file is fully local (or trigger + wait for hydration)
166	        await ensureHydrated(target.localPath, {
167	          onProgress: (s) =>
168	            log.debug(`Hydrating ${target.localPath}: ${s.state} ${s.bytesDone ?? 0}B`),
169	        });
170	        sourcePath = target.localPath;
171	        sourceProvider = "seafile";
172	        seafileObjId =
173	          (await getSeafileObjId(target.mapping.libraryId, target.pathInLib, config)) ?? undefined;
174	      } catch (e) {
175	        if (!config.synologyFallbackAllowed) throw e;
176	        log.warn(`Seafile resolution failed, falling back to Synology: ${(e as Error).message}`);
177	      }
178	    } else if (!config.synologyFallbackAllowed) {
179	      throw new Error(
180	        "Seafile/SeaDrive is unavailable and fallback is not enabled for this account." +
181	          (health.detail ? `\n\n${health.detail}` : ""),
182	      );
183	    } else {
184	      log.warn(`Seafile unavailable (${health.detail ?? "unknown"}); falling back to Synology.`);
185	    }
186	  }
187	
188	  if (!sourcePath) {
189	    sourcePath = resolveSynologyPath();
190	    sourceProvider = "synology";
191	  }
192	
193	  if (!existsSync(sourcePath)) {
194	    throw new Error(
195	      `File not found locally: ${sourcePath}\n\nIt may not have synced yet. Check your Seafile or Synology Drive client.`,
196	    );
197	  }
198	
199	  const copied = await copyToWorkspace(
200	    sourcePath,
201	    checkout_id,
202	    asset.filename,
203	    config.workspacePath,
204	  );
205	
206	  const destDir = checkoutDir(config.workspacePath, checkout_id);
207	  writeCheckoutMeta(destDir, {
208	    checkout_id,
209	    asset_id: asset.asset_id,
210	    root_id: asset.relative_path.split("/")[0],
211	    relative_path: asset.relative_path,
212	    filename: asset.filename,
213	    checked_out_at: new Date().toISOString(),
214	    source_hash: asset.expected_hash ?? copied.hash,
215	    source_size: asset.expected_size ?? copied.size,
216	    dam_url: `${config.damUrl}/assets/${asset.asset_id}`,
217	    source_provider: sourceProvider,
218	    source_local_path: sourcePath,
219	    seafile_obj_id: seafileObjId,
220	  });
221	
222	  const record: CheckoutRecord = {
223	    id: checkout_id,
224	    assetId: asset.asset_id,
225	    userId: "",
226	    deviceId: config.deviceId,
227	    status: "active",
228	    checkedOutAt: new Date().toISOString(),
229	    checkedInAt: null,
230	    filename: asset.filename,
231	    relativePath: asset.relative_path,
232	    rootId: asset.relative_path.split("/")[0],
233	    sourceHash: asset.expected_hash ?? copied.hash,
234	    sourceSize: asset.expected_size ?? copied.size,
