250	  }
251	
252	  return { checkoutId: checkout_id, workspacePath: copied.workspacePath };
253	}
254	
255	// ── Check-in ──────────────────────────────────────────────────────────────────
256	
257	export async function checkin(checkoutId: string): Promise<void> {
258	  const record = active.get(checkoutId);
259	  if (!record) throw new Error(`Checkout ${checkoutId} not found`);
260	
261	  const config = getConfig();
262	
263	  updateStatus(checkoutId, "checkin_queued");
264	
265	  if (!existsSync(record.workspacePath)) {
266	    throw new Error(`Workspace file missing: ${record.workspacePath}`);
267	  }
268	
269	  // Wait for file to stop saving
270	  await waitForFileStable(record.workspacePath);
271	
272	  // Snapshot
273	  const snap = await createSnapshot(
274	    record.workspacePath,
275	    checkoutId,
276	    record.filename,
277	    config.workspacePath,
278	  );
279	
280	  // Tell DAM we're about to upload
281	  const instructions = await apiPrepareCheckin({
282	    checkout_id: checkoutId,
283	    snapshot_hash: snap.hash,
284	    snapshot_size: snap.size,
285	  });
286	
287	  record.snapshotPath = snap.snapshotPath;
288	
289	  // Enqueue async upload
290	  enqueue({
291	    checkoutId,
292	    snapshotPath: snap.snapshotPath,
293	    uploadMethod: config.preferredProvider === "synology" ? "smb_local" : "synology_file_station",
294	    synologyUrl: instructions.upload_instructions.synology_url,
295	    synologyPort: instructions.upload_instructions.synology_port,
296	    relativePath: instructions.upload_instructions.relative_path,
297	    filename: instructions.upload_instructions.filename,
