308	
309	// ── Discard ───────────────────────────────────────────────────────────────────
310	
311	export async function discard(checkoutId: string): Promise<void> {
312	  await apiDiscard(checkoutId);
313	  stopWatcher(checkoutId);
314	  active.delete(checkoutId);
