332	// ── Accessors ─────────────────────────────────────────────────────────────────
333	
334	export function getActiveCheckouts(): CheckoutRecord[] {
335	  return Array.from(active.values());
336	}
337	
338	export function updateUploadProgress(checkoutId: string, percent: number): void {
339	  const record = active.get(checkoutId);
340	  if (!record) return;
341	  record.uploadProgress = percent;
342	  if (percent >= 100) {
343	    record.status = "complete";
344	    active.delete(checkoutId);
345	    stopWatcher(checkoutId);
346	  }
