351	  const record = active.get(checkoutId);
352	  if (!record) return;
353	  record.status = status;
354	  notify();
355	}
356	
357	/**
358	 * The upload finished but the server is holding the lock in 'verifying' until
359	 * the bridge agent confirms the file landed intact on the Synology (Seafile
360	 * sources). Keep the checkout visible — it is NOT done yet.
361	 */
362	export function markVerifying(checkoutId: string): void {
363	  const record = active.get(checkoutId);
364	  if (!record) return;
365	  record.status = "verifying";
366	  record.uploadProgress = 100;
367	  record.errorMessage = null;
368	  notify();
369	}
370	
371	/**
372	 * Reconcile locally-'verifying' checkouts against the server. The bridge agent
373	 * flips them to 'complete' once it confirms receipt (they drop out of the open
374	 * list), or the server flags verify_failed_at if the file never arrives intact
375	 * before the deadline (lock stays held — surfaced as an error to the user).
376	 * Only touches records currently in 'verifying' so it never disturbs in-flight
377	 * uploads or active edits.
378	 */
379	export async function reconcileVerifyingCheckouts(): Promise<void> {
380	  const verifying = getActiveCheckouts().filter((r) => r.status === "verifying");
381	  if (verifying.length === 0) return;
382	
383	  let res;
384	  try {
385	    res = await getOpenCheckouts();
386	  } catch (e) {
387	    log.warn("Could not reconcile verifying checkouts:", (e as Error).message);
388	    return;
389	  }
390	
391	  const serverById = new Map((res.checkouts ?? []).map((c) => [c.id, c]));
392	  let changed = false;
393	
394	  for (const rec of verifying) {
395	    const server = serverById.get(rec.id) as
396	      | {
397	          status: string;
398	          verify_failed_at?: string | null;
399	          verify_error?: string | null;
400	          redrive_requested?: boolean;
401	        }
402	      | undefined;
403	
404	    if (!server) {
405	      // No longer open → bridge agent confirmed receipt and it completed.
406	      rec.status = "complete";
407	      active.delete(rec.id);
408	      stopWatcher(rec.id);
409	      redriving.delete(rec.id);
410	      changed = true;
411	      continue;
412	    }
413	
414	    if (server.status === "error") {
415	      // Auto-resolved past the deadline: lock released, asset freed. Surface the
416	      // server's explanation so the designer knows to check in again.
417	      rec.status = "error";
418	      rec.errorMessage =
419	        server.verify_error ??
420	        "Check-in could not be confirmed. Your work is saved locally — please check in again.";
421	      redriving.delete(rec.id);
422	      changed = true;
423	      continue;
424	    }
425	
426	    if (server.redrive_requested) {
427	      // Server asked us to re-upload the retained snapshot to self-heal.
428	      void triggerRedrive(rec);
429	    }
430	
431	    if (server.verify_failed_at) {
432	      // Still locked, but flagged — verification hasn't succeeded yet.
433	      rec.errorMessage =
434	        server.verify_error ??
435	        "Still confirming this check-in reached the server…";
436	      changed = true;
437	    } else if (rec.errorMessage) {
438	      // Recovered (e.g. a re-drive cleared the flag) — drop the stale message.
439	      rec.errorMessage = null;
440	      changed = true;
441	    }
442	  }
443	
444	  if (changed) notify();
445	}
446	
447	/**
448	 * Re-upload a stuck check-in's snapshot to the Synology. Best-effort: if the
449	 * snapshot is no longer available locally (e.g. after an app restart) we skip and
450	 * let the server auto-resolve at its deadline.
451	 */
452	async function triggerRedrive(rec: CheckoutRecord): Promise<void> {
453	  if (redriving.has(rec.id)) return;
454	  if (!rec.snapshotPath || !existsSync(rec.snapshotPath)) {
455	    log.warn(`Re-drive requested for ${rec.id} but snapshot is unavailable locally — leaving for server auto-resolve`);
456	    return;
457	  }
458	  redriving.add(rec.id);
459	  try {
460	    const { upload_instructions: ui } = await apiRedrive(rec.id);
461	    const config = getConfig();
462	    enqueue({
463	      checkoutId: rec.id,
464	      snapshotPath: rec.snapshotPath,
465	      uploadMethod: config.preferredProvider === "synology" ? "smb_local" : "synology_file_station",
466	      synologyUrl: ui.synology_url,
467	      synologyPort: ui.synology_port,
468	      relativePath: ui.relative_path,
469	      filename: ui.filename,
470	      tempSuffix: ui.temp_suffix,
471	      retryCount: 0,
472	      addedAt: Date.now(),
473	      sourceProvider: rec.sourceProvider,
474	      seafileObjId: rec.seafileObjId,
475	      isRedrive: true,
476	    });
477	    log.info(`Re-driving check-in ${rec.id} (re-uploading snapshot)`);
478	  } catch (e) {
479	    log.warn(`Re-drive trigger failed for ${rec.id}:`, (e as Error).message);
480	  } finally {
481	    // Clear shortly after so a later genuine re-request can proceed; the server
482	    // clears redrive_requested immediately, so this mainly guards the in-flight gap.
483	    redriving.delete(rec.id);
484	  }
485	}
486	
487	// ── File watcher ──────────────────────────────────────────────────────────────
488	
489	function watchFile(checkoutId: string, filePath: string): void {
490	  if (!existsSync(filePath)) return;
491	  stopWatcher(checkoutId);
492	
493	  const watcher = chokidar.watch(filePath, {
494	    persistent: true,
495	    ignoreInitial: true,
496	    awaitWriteFinish: { stabilityThreshold: 2000, pollInterval: 300 },
497	  });
498	
499	  watcher.on("change", () => {
500	    const record = active.get(checkoutId);
501	    if (!record) return;
502	    log.debug(`File changed: ${filePath}`);
503	    notify();
504	  });
505	
506	  watcher.on("unlink", () => {
507	    const record = active.get(checkoutId);
508	    if (!record) return;
509	    record.errorMessage = "Workspace file was deleted.";
510	    updateStatus(checkoutId, "error");
511	  });
512	
513	  watchers.set(checkoutId, watcher);
514	}
515	
516	function stopWatcher(checkoutId: string): void {
517	  const w = watchers.get(checkoutId);
518	  if (w) {
519	    w.close();
520	    watchers.delete(checkoutId);
521	  }
522	}
