1	/**
2	 * Seafile / SeaDrive adapter.
3	 *
4	 * The Helper *supervises* an officially-installed SeaDrive client — it never
5	 * forks, embeds, or writes into the shared mount as the primary workflow.
6	 * Everything here is read-only detection + path mapping + hydration waiting.
7	 *
8	 * Boundary (see docs/POPDAM_HELPER.md / HANDOFF.md):
9	 *  - Detect the installed client and its mount root.
10	 *  - Map a PopDAM root_id + relative_path to a SeaDrive library path.
11	 *  - Confirm a file is hydrated (fully local) or trigger + wait for hydration.
12	 *  - Optionally fetch the Seafile REST `obj_id` for source_version (needs a token).
13	 *
14	 * No API token required for the first slice: getSeafileObjId() returns null
15	 * when no token/server URL is configured, which is an accepted state.
16	 */
17	
18	import { existsSync, statSync, openSync, closeSync, readSync } from "fs";
19	import { join, normalize, isAbsolute, sep } from "path";
20	import { homedir } from "os";
21	import { execFileSync } from "child_process";
22	import { loadToken } from "./credentials";
23	import { log } from "./logger";
24	import type {
25	  LocalConfig,
26	  SeafileLibraryMapping,
27	  StorageHealth,
28	  HydrationStatus,
29	} from "@shared/types";
30	
31	// ── Mount-root detection ────────────────────────────────────────────────────
32	
33	/**
34	 * Resolve the SeaDrive mount root. Order:
35	 *  1. Explicit config.seaDriveRoot (user override / previously detected).
36	 *  2. Platform default (~/SeaDrive on macOS, %USERPROFILE%\SeaDrive on Windows).
37	 * Returns the path only if it exists on disk; otherwise null.
38	 */
39	export function detectSeaDriveRoot(config: LocalConfig): string | null {
40	  const candidates: string[] = [];
41	  if (config.seaDriveRoot) candidates.push(config.seaDriveRoot);
42	  candidates.push(join(homedir(), "SeaDrive"));
43	
44	  for (const c of candidates) {
45	    try {
46	      if (existsSync(c) && statSync(c).isDirectory()) return c;
47	    } catch {
48	      /* ignore */
49	    }
50	  }
51	  return null;
52	}
53	
54	// ── Install / process detection ─────────────────────────────────────────────
55	
56	/**
57	 * Best-effort check for an installed SeaDrive (virtual-drive) client.
58	 * We only support SeaDrive — never the legacy Seafile *sync* client, which would
59	 * try to fully download a library to local disk. Do not add sync-client paths here.
60	 */
61	export function isSeaDriveInstalled(): boolean {
62	  const paths =
63	    process.platform === "darwin"
64	      ? [
65	          "/Applications/SeaDrive.app",
66	          join(homedir(), "Applications/SeaDrive.app"),
67	        ]
68	      : [
69	          "C:\\Program Files\\SeaDrive\\seadrive.exe",
70	          "C:\\Program Files (x86)\\SeaDrive\\seadrive.exe",
71	        ];
72	  return paths.some((p) => {
73	    try {
74	      return existsSync(p);
75	    } catch {
76	      return false;
77	    }
78	  });
79	}
80	
81	/** Best-effort process-list check. Never throws — returns false on any error. */
82	export function isSeaDriveRunning(): boolean {
83	  try {
84	    if (process.platform === "darwin") {
85	      // pgrep exits non-zero (throws) when nothing matches.
86	      const out = execFileSync("pgrep", ["-il", "seadrive"], {
87	        encoding: "utf-8",
88	        timeout: 3000,
89	      });
90	      return out.trim().length > 0;
91	    }
92	    // Windows
93	    const out = execFileSync(
94	      "tasklist",
95	      ["/FI", "IMAGENAME eq seadrive.exe", "/NH"],
96	      { encoding: "utf-8", timeout: 3000 },
97	    );
98	    return /seadrive\.exe/i.test(out);
99	  } catch {
100	    return false;
101	  }
102	}
103	
104	// ── Path mapping ────────────────────────────────────────────────────────────
105	
106	/** Reject relative paths that try to escape the library root. */
107	function sanitizeRelativePath(p: string): string {
108	  const normalized = normalize(p.replace(/\\/g, "/"));
109	  if (
110	    isAbsolute(normalized) ||
111	    normalized.startsWith("..") ||
112	    normalized.includes(".." + sep) ||
113	    /^[a-zA-Z]:/.test(normalized) ||
114	    normalized.startsWith("//") ||
115	    normalized.startsWith("\\\\")
116	  ) {
117	    throw new Error(`Unsafe relative path rejected: "${p}"`);
118	  }
119	  return normalized;
120	}
121	
122	function normalizeRel(p: string): string {
123	  return p.replace(/\\/g, "/").replace(/^\/+/, "").replace(/\/+$/, "");
124	}
125	
126	/**
127	 * Find the Seafile library whose pathPrefix is the longest match for a given
128	 * relative_path. A PopDAM root can hold multiple libraries as subfolders
129	 * (e.g. "Decor/Character Licensed" and "Decor/Generic Decor"), so we match on
130	 * the full prefix, not just the first segment.
131	 */
132	function findMappingForPath(
133	  relativePath: string,
134	  config: LocalConfig,
135	): SeafileLibraryMapping | null {
136	  const rel = normalizeRel(relativePath);
137	  let best: SeafileLibraryMapping | null = null;
138	  let bestLen = -1;
139	  for (const m of config.seafileLibraries ?? []) {
140	    const prefix = normalizeRel(m.pathPrefix);
141	    if (rel === prefix || rel.startsWith(prefix + "/")) {
142	      if (prefix.length > bestLen) {
143	        best = m;
144	        bestLen = prefix.length;
145	      }
146	    }
147	  }
148	  return best;
149	}
150	
151	export interface SeafileTarget {
152	  mapping: SeafileLibraryMapping;
153	  localPath: string;  // absolute path under the SeaDrive mount
154	  pathInLib: string;  // path within the Seafile library (relative_path minus the prefix)
155	}
156	
157	/**
158	 * Resolve a PopDAM relative_path to a SeaDrive target: the matching library,
159	 * the absolute local path, and the in-library path.
160	 *
161	 * Throws on: no mount root, no library covering the path, or unsafe path.
162	 */
163	export function resolveSeafileTarget(
164	  relativePath: string,
165	  config: LocalConfig,
166	): SeafileTarget {
167	  const root = detectSeaDriveRoot(config);
168	  if (!root) throw new Error("SeaDrive mount root not found.");
169	
170	  const mapping = findMappingForPath(relativePath, config);
171	  if (!mapping) {
172	    throw new Error(`No Seafile library covers "${relativePath}".`);
173	  }
174	
175	  const rel = normalizeRel(relativePath);
176	  const prefix = normalizeRel(mapping.pathPrefix);
177	  const remainder = rel === prefix ? "" : rel.slice(prefix.length + 1);
178	  const pathInLib = remainder ? sanitizeRelativePath(remainder) : "";
179	  const localPath = pathInLib
180	    ? join(root, mapping.seaDriveFolder, pathInLib)
181	    : join(root, mapping.seaDriveFolder);
182	  return { mapping, localPath, pathInLib };
183	}
184	
185	/** Convenience wrapper returning just the absolute local path. */
186	export function resolveSeafilePath(relativePath: string, config: LocalConfig): string {
187	  return resolveSeafileTarget(relativePath, config).localPath;
188	}
189	
190	/** Library folders that are actually present (mounted) under the SeaDrive root. */
191	export function getMountedLibraries(config: LocalConfig): string[] {
192	  const root = detectSeaDriveRoot(config);
193	  if (!root) return [];
194	  return (config.seafileLibraries ?? [])
195	    .map((m) => m.seaDriveFolder)
196	    .filter((folder) => {
197	      try {
198	        return existsSync(join(root, folder));
199	      } catch {
200	        return false;
201	      }
202	    });
203	}
204	
205	// ── Health ──────────────────────────────────────────────────────────────────
206	
207	export interface SeafileHealth extends StorageHealth {
208	  provider: "seafile";
209	  installed: boolean;
210	  running: boolean;
211	  root: string | null;
212	  librariesConfigured: string[];
213	  librariesMounted: string[];
214	  librariesMissing: string[];
215	}
216	
217	export function getSeafileHealth(config: LocalConfig): SeafileHealth {
218	  const installed = isSeaDriveInstalled();
219	  const running = isSeaDriveRunning();
220	  const root = detectSeaDriveRoot(config);
221	  const configured = (config.seafileLibraries ?? []).map((m) => m.seaDriveFolder);
222	  const mounted = getMountedLibraries(config);
223	  const missing = configured.filter((f) => !mounted.includes(f));
224	
225	  let detail: string | undefined;
226	  if (!installed) detail = "SeaDrive client not detected.";
227	  else if (!root) detail = "SeaDrive mount root not found.";
228	  else if (!running) detail = "SeaDrive client is not running.";
229	  else if (missing.length) detail = `Libraries not mounted: ${missing.join(", ")}`;
230	
231	  const available = !!root && missing.length === 0;
232	  return {
233	    provider: "seafile",
234	    available,
235	    installed,
236	    running,
237	    root,
238	    librariesConfigured: configured,
239	    librariesMounted: mounted,
240	    librariesMissing: missing,
241	    detail,
242	  };
243	}
244	
245	// ── Hydration ───────────────────────────────────────────────────────────────
246	
247	/**
248	 * SeaDrive presents cloud-only files as zero-byte (or sparse) placeholders that
249	 * fill in on access. We treat a readable, non-empty, size-stable file as local.
250	 */
