  "/Users",
  "/home",
  "/tmp",
  "/var",
  "/etc",
  "/System",
  "/Library",
];

// Minimum depth below a user home dir before a path is considered safe
export const MIN_PATH_DEPTH = 2;

// File stability check
export const STABILITY_WAIT_MS = 3000;
