  // Dev mode — register with electron executable
  if (process.argv.length >= 2) {
    app.setAsDefaultProtocolClient("popdam", process.execPath, [process.argv[1]]);
  }
} else {
  app.setAsDefaultProtocolClient("popdam");
}

registerProtocol();

