            local_path: r.local_path,
          })),
          storageProviders: {
            seafile: {
              available: seafile.available,
              root: seafile.root,
              libraries: seafile.librariesMounted,
            },
            synology: { available: synologyAvailable },
          },
        }, origin);
        return;
      }

